import React, { useEffect, useRef, useState } from 'react';
import styled from 'styled-components';
import { motion, useInView } from 'framer-motion';

const StatsGrid = styled.div`
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(150px, 1fr));
  gap: var(--space-lg);
  margin-top: var(--space-2xl);
  
  @media (max-width: 640px) {
    grid-template-columns: repeat(2, 1fr);
    gap: var(--space-md);
    margin-top: var(--space-xl);
  }
  
  @media (max-width: 480px) {
    gap: var(--space-sm);
  }
`;

const StatContainer = styled(motion.div)`
  text-align: center;
  padding: var(--space-xl);
  background: rgba(153, 69, 255, 0.05);
  border: 1px solid rgba(153, 69, 255, 0.2);
  border-radius: var(--radius-xl);
  position: relative;
  overflow: hidden;
  transition: all var(--duration-normal) var(--ease-out-expo);
  
  @media (max-width: 640px) {
    padding: var(--space-lg);
  }
  
  @media (max-width: 480px) {
    padding: var(--space-md);
    border-radius: var(--radius-lg);
  }
  
  &:hover {
    transform: translateY(-5px);
    border-color: var(--color-neon-purple);
    background: rgba(153, 69, 255, 0.1);
    
    &::before {
      transform: translateX(0);
    }
  }
  
  &::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: linear-gradient(90deg, transparent 0%, rgba(153, 69, 255, 0.1) 50%, transparent 100%);
    transform: translateX(-100%);
    transition: transform var(--duration-slow) var(--ease-out-expo);
  }
`;

const StatValue = styled.div`
  font-size: var(--text-4xl);
  font-weight: 900;
  color: var(--color-neon-purple);
  margin-bottom: var(--space-sm);
  font-family: var(--font-mono);
  position: relative;
  z-index: 1;
  
  @media (max-width: 768px) {
    font-size: var(--text-3xl);
  }
`;

const StatLabel = styled.div`
  font-size: var(--text-base);
  color: var(--color-text-secondary);
  text-transform: uppercase;
  letter-spacing: var(--tracking-wider);
  font-weight: 600;
  position: relative;
  z-index: 1;
`;

const SingleStat = ({ value, suffix = '', label, delay = 0 }) => {
  const [count, setCount] = useState(0);
  const containerRef = useRef(null);
  const isInView = useInView(containerRef, { once: true, margin: "-50px" });
  const hasAnimated = useRef(false);
  
  useEffect(() => {
    if (!isInView || hasAnimated.current || !value) return;
    hasAnimated.current = true;
    
    const duration = 2000;
    const steps = 60;
    const stepDuration = duration / steps;
    
    let currentStep = 0;
    
    const timer = setInterval(() => {
      currentStep++;
      
      if (currentStep === steps) {
        setCount(value);
        clearInterval(timer);
      } else {
        // Easing function for smooth animation
        const progress = currentStep / steps;
        const easedProgress = 1 - Math.pow(1 - progress, 3); // Cubic ease-out
        setCount(Math.floor(value * easedProgress));
      }
    }, stepDuration);
    
    return () => clearInterval(timer);
  }, [isInView, value]);
  
  return (
    <StatContainer
      ref={containerRef}
      initial={{ scale: 0.8, opacity: 0 }}
      animate={isInView ? { scale: 1, opacity: 1 } : {}}
      transition={{ duration: 0.5, delay, ease: [0.6, -0.05, 0.01, 0.99] }}
      whileHover={{ scale: 1.05 }}
    >
      <StatValue>
        {count.toLocaleString()}{suffix}
      </StatValue>
      <StatLabel>{label}</StatLabel>
    </StatContainer>
  );
};

const StatsCounter = () => {
  const stats = [
    { value: 50, suffix: '+', label: 'Projects' },
    { value: 30, suffix: '+', label: 'Clients' },
    { value: 5, suffix: '+', label: 'Years' }
  ];

  return (
    <StatsGrid>
      {stats.map((stat, index) => (
        <SingleStat
          key={index}
          value={stat.value}
          suffix={stat.suffix}
          label={stat.label}
          delay={index * 0.1}
        />
      ))}
    </StatsGrid>
  );
};

export default StatsCounter;