import React, { useRef, useEffect } from 'react';
import styled from 'styled-components';
import { motion } from 'framer-motion';
import gsap from 'gsap';
import { ScrollTrigger } from 'gsap/ScrollTrigger';

gsap.registerPlugin(ScrollTrigger);

const TimelineContainer = styled(motion.div)`
  position: relative;
  padding: var(--space-2xl) 0;
  
  @media (max-width: 1024px) {
    padding: var(--space-xl) 0;
  }
  
  @media (max-width: 768px) {
    padding: var(--space-lg) 0;
  }
`;

const TimelineLine = styled.div`
  position: absolute;
  left: 50%;
  top: 0;
  bottom: 0;
  width: 2px;
  background: rgba(153, 69, 255, 0.2);
  transform: translateX(-50%);
  
  @media (max-width: 768px) {
    left: 20px;
    transform: none;
  }
  
  &::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 0%;
    background: var(--gradient-neon);
    transition: height 1.5s ease-out;
  }
  
  &.active::before {
    height: 100%;
  }
`;

const TimelineItem = styled(motion.div)`
  position: relative;
  width: 50%;
  padding: var(--space-xl) var(--space-2xl);
  margin-left: ${props => props.$align === 'right' ? '50%' : '0'};
  
  @media (max-width: 768px) {
    width: 100%;
    margin-left: 0;
    padding: var(--space-lg) 0 var(--space-lg) calc(40px + var(--space-lg));
  }
  
  @media (max-width: 480px) {
    padding: var(--space-md) 0 var(--space-md) calc(40px + var(--space-md));
  }
`;

const TimelineContent = styled(motion.div)`
  position: relative;
  background: var(--color-surface);
  padding: var(--space-xl);
  border-radius: var(--radius-lg);
  box-shadow: 0 10px 30px rgba(0, 0, 0, 0.3);
  transition: all 0.3s ease;
  
  &:hover {
    transform: translateY(-5px);
    box-shadow: 0 15px 40px rgba(153, 69, 255, 0.2);
  }
  
  @media (max-width: 768px) {
    padding: var(--space-lg);
    
    &:hover {
      transform: translateY(-3px);
    }
  }
  
  @media (max-width: 480px) {
    padding: var(--space-md);
  }
`;

const TimelineDot = styled(motion.div)`
  position: absolute;
  top: var(--space-xl);
  ${props => props.$align === 'right' ? 'left: -8px;' : 'right: -8px;'}
  width: 16px;
  height: 16px;
  background: var(--color-neon-purple);
  border-radius: 50%;
  box-shadow: 0 0 0 4px var(--color-surface), 0 0 0 8px rgba(153, 69, 255, 0.3);
  z-index: 10;
  
  @media (max-width: 768px) {
    left: 12px;
    right: auto;
    top: var(--space-lg);
  }
  
  @media (max-width: 480px) {
    width: 14px;
    height: 14px;
    left: 13px;
    top: var(--space-md);
    box-shadow: 0 0 0 3px var(--color-surface), 0 0 0 6px rgba(153, 69, 255, 0.3);
  }
`;

const TimelineYear = styled(motion.span)`
  position: absolute;
  top: var(--space-xl);
  ${props => props.$align === 'right' ? 'right: calc(100% + var(--space-2xl));' : 'left: calc(100% + var(--space-2xl));'}
  font-size: var(--text-2xl);
  font-weight: 900;
  color: var(--color-neon-purple);
  
  @media (max-width: 768px) {
    position: static;
    display: block;
    margin-bottom: var(--space-sm);
    font-size: var(--text-xl);
  }
`;

const TimelineTitle = styled.h3`
  font-size: var(--text-xl);
  font-weight: 700;
  color: var(--color-white);
  margin-bottom: var(--space-sm);
  
  @media (max-width: 768px) {
    font-size: var(--text-lg);
  }
  
  @media (max-width: 480px) {
    font-size: var(--text-base);
  }
`;

const TimelineDescription = styled.p`
  font-size: var(--text-base);
  color: var(--color-text-secondary);
  line-height: 1.6;
  
  @media (max-width: 768px) {
    font-size: var(--text-sm);
  }
  
  @media (max-width: 480px) {
    font-size: var(--text-xs);
    line-height: 1.5;
  }
`;

const Timeline = () => {
  const containerRef = useRef(null);
  const lineRef = useRef(null);
  const itemRefs = useRef([]);

const milestones = [
  {
    year: '2020',
    title: 'Entering FiveM Development',
    description: 'Started scripting in Lua for FiveM, building custom features and small-scale server projects.',
    align: 'left'
  },
  {
    year: '2021',
    title: 'Major Server Development',
    description: 'Created advanced systems and frameworks for servers with 100+ active players, expanding technical expertise.',
    align: 'right'
  },
  {
    year: '2022',
    title: 'High-Performance Server Specialist',
    description: 'Optimized large-scale servers to handle 500+ concurrent players with minimal latency and stable performance.',
    align: 'left'
  },
  {
    year: '2023',
    title: 'Open Source Contributor',
    description: 'Contributed significant improvements and features to ESX Framework and other major FiveM community projects.',
    align: 'right'
  },
  {
    year: '2024',
    title: 'ESX Framework Development Lead',
    description: 'Led technical development for ESX, supporting 90,000+ servers worldwide with critical updates and new features.',
    align: 'left'
  },
  {
    year: '2025',
    title: 'ESX Framework Project Lead',
    description: 'Overseeing the entire ESX project, managing development, community engagement, and long-term vision.',
    align: 'right'
  }
];

  useEffect(() => {
    const container = containerRef.current;
    const line = lineRef.current;
    const items = itemRefs.current;

    if (!container || !line || items.length === 0) return;

    // Wait for DOM to be ready
    setTimeout(() => {
      try {
        // Timeline line progress animation
        gsap.fromTo(line,
          { '--progress': '0%' },
          {
            '--progress': '100%',
            ease: 'none',
            scrollTrigger: {
              trigger: container,
              start: 'top 80%',
              end: 'bottom 60%',
              scrub: 1,
              onUpdate: (self) => {
                if (line && line.style) {
                  line.style.setProperty('--progress', `${self.progress * 100}%`);
                }
              }
            }
          }
        );
      } catch (error) {
        console.warn('Timeline line animation failed:', error);
      }

      // Timeline items animations
      items.forEach((item, index) => {
        if (!item) return;

        try {
          const timeline = gsap.timeline({
            scrollTrigger: {
              trigger: item,
              start: 'top 85%',
              toggleActions: 'play none none reverse'
            }
          });

          // Animate from left or right based on alignment
          const xStart = milestones[index] && milestones[index].align === 'left' ? -50 : 50;

          timeline
            .fromTo(item,
              { 
                opacity: 0, 
                x: xStart,
                scale: 0.9
              },
              { 
                opacity: 1, 
                x: 0,
                scale: 1,
                duration: 0.8,
                ease: 'power2.out'
              }
            );
          
          const dot = item.querySelector('.timeline-dot');
          const year = item.querySelector('.timeline-year');
          
          if (dot) {
            timeline.fromTo(dot,
              { scale: 0 },
              { 
                scale: 1, 
                duration: 0.4,
                ease: 'back.out(1.7)'
              },
              '-=0.4'
            );
          }
          
          if (year) {
            timeline.fromTo(year,
              { 
                opacity: 0,
                scale: 0.8
              },
              { 
                opacity: 1,
                scale: 1,
                duration: 0.4
              },
              '-=0.2'
            );
          }
        } catch (error) {
          console.warn(`Timeline item ${index} animation failed:`, error);
        }
      });

      // Add CSS for the progress line
      try {
        const style = document.createElement('style');
        style.setAttribute('data-timeline', 'true');
        if (line && line.className) {
          style.textContent = `
            ${line.className.split(' ').map(c => `.${c}`).join('')}::before {
              height: var(--progress, 0%);
            }
          `;
          document.head.appendChild(style);
        }
      } catch (error) {
        console.warn('Timeline CSS injection failed:', error);
      }
    }, 100);

    // Cleanup
    return () => {
      ScrollTrigger.getAll().forEach(trigger => {
        if (trigger.trigger === container || items.includes(trigger.trigger)) {
          trigger.kill();
        }
      });
      // Remove any dynamic styles
      const dynamicStyles = document.querySelectorAll('style[data-timeline]');
      dynamicStyles.forEach(s => s.remove());
    };
  }, [milestones]);

  return (
    <TimelineContainer ref={containerRef}>
      <TimelineLine ref={lineRef} />
      
      {milestones.map((milestone, index) => (
        <TimelineItem
          key={index}
          ref={el => itemRefs.current[index] = el}
          $align={milestone.align}
        >
          <TimelineDot 
            className="timeline-dot"
            $align={milestone.align} 
          />
          <TimelineYear 
            className="timeline-year"
            $align={milestone.align}
          >
            {milestone.year}
          </TimelineYear>
          <TimelineContent>
            <TimelineTitle>{milestone.title}</TimelineTitle>
            <TimelineDescription>{milestone.description}</TimelineDescription>
          </TimelineContent>
        </TimelineItem>
      ))}
    </TimelineContainer>
  );
};

export default Timeline;