import React, { useRef, useEffect, useCallback } from 'react';
import styled from 'styled-components';
import { motion } from 'framer-motion';
import gsap from 'gsap';
import { ScrollTrigger } from 'gsap/ScrollTrigger';
import Timeline from './Timeline';
import StatsCounter from './StatsCounter';

gsap.registerPlugin(ScrollTrigger);

const AboutSection = styled.section`
  min-height: 100vh;
  padding: var(--space-5xl) 0;
  position: relative;
  background: linear-gradient(180deg, var(--color-deep-purple) 0%, var(--color-dark-surface) 100%);
  overflow: hidden;
  /* Prevent margin collapse */
  &::before {
    content: '';
    display: table;
  }
  &::after {
    content: '';
    display: table;
    clear: both;
  }
  
  @media (max-width: 768px) {
    padding: var(--space-4xl) 0;
    min-height: auto;
  }
  
  @media (max-width: 480px) {
    padding: var(--space-3xl) 0;
  }
`;

const Container = styled.div`
  max-width: 1440px;
  margin: 0 auto;
  padding: 0 var(--space-xl);
  position: relative;
  z-index: 2;
  
  @media (max-width: 768px) {
    padding: 0 var(--space-lg);
  }
  
  @media (max-width: 480px) {
    padding: 0 var(--space-md);
  }
`;

const Grid = styled.div`
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: var(--space-4xl);
  align-items: center;
  
  @media (max-width: 1024px) {
    grid-template-columns: 1fr;
    gap: var(--space-3xl);
  }
`;

const ContentColumn = styled(motion.div)``;

const SectionLabel = styled(motion.span)`
  display: inline-block;
  font-size: var(--text-sm);
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: var(--tracking-wider);
  color: var(--color-neon-purple);
  margin-bottom: var(--space-md);
`;

const Title = styled(motion.h2)`
  font-size: var(--text-5xl);
  font-weight: 900;
  color: var(--color-white);
  margin-bottom: var(--space-xl);
  line-height: 1.1;
  
  @media (max-width: 1024px) {
    font-size: var(--text-4xl);
  }
  
  @media (max-width: 768px) {
    font-size: clamp(2rem, 8vw, 3rem);
    margin-bottom: var(--space-lg);
  }
  
  @media (max-width: 480px) {
    font-size: clamp(1.75rem, 9vw, 2.5rem);
  }
`;

const Description = styled(motion.p)`
  font-size: var(--text-lg);
  color: var(--color-text-secondary);
  line-height: 1.8;
  margin-bottom: var(--space-2xl);
  
  @media (max-width: 768px) {
    font-size: var(--text-base);
    line-height: 1.7;
    margin-bottom: var(--space-xl);
  }
  
  @media (max-width: 480px) {
    font-size: var(--text-sm);
    line-height: 1.6;
  }
`;

const FeatureGrid = styled(motion.div)`
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: var(--space-lg);
  margin-bottom: var(--space-3xl);
  
  @media (max-width: 640px) {
    grid-template-columns: 1fr;
    gap: var(--space-md);
    margin-bottom: var(--space-2xl);
  }
`;

const FeatureItem = styled(motion.div)`
  display: flex;
  align-items: flex-start;
  gap: var(--space-md);
`;

const FeatureIcon = styled.div`
  width: 24px;
  height: 24px;
  flex-shrink: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  color: var(--color-neon-purple);
`;

const FeatureText = styled.div`
  flex: 1;
`;

const FeatureTitle = styled.h4`
  font-size: var(--text-base);
  font-weight: 600;
  color: var(--color-white);
  margin-bottom: var(--space-xs);
  
  @media (max-width: 480px) {
    font-size: var(--text-sm);
  }
`;

const FeatureDescription = styled.p`
  font-size: var(--text-sm);
  color: var(--color-text-secondary);
  line-height: 1.6;
`;

const FloatingShape = styled(motion.div)`
  position: absolute;
  width: 600px;
  height: 600px;
  border-radius: 50%;
  background: radial-gradient(circle, var(--color-neon-purple) 0%, transparent 70%);
  opacity: 0.1;
  filter: blur(100px);
  pointer-events: none;
  
  @media (max-width: 768px) {
    width: 400px;
    height: 400px;
    filter: blur(80px);
    opacity: 0.08;
  }
  
  @media (max-width: 480px) {
    display: none; /* Hide on small screens for performance */
  }
`;

const features = [
  {
    icon: '⚡',
    title: 'Performance First',
    description: 'Optimized code for smooth gameplay'
  },
  {
    icon: '🎨',
    title: 'Custom Solutions',
    description: 'Tailored to your server\'s needs'
  },
  {
    icon: '🚀',
    title: 'Scalable Systems',
    description: 'From small communities to 1000+ players'
  },
  {
    icon: '🛡️',
    title: 'Reliable Support',
    description: 'Long-term partnership and maintenance'
  }
];

const About = React.memo(() => {
  const sectionRef = useRef(null);
  const contentRef = useRef(null);
  const floatingRef = useRef(null);

  useEffect(() => {
    const section = sectionRef.current;
    const content = contentRef.current;
    const floating = floatingRef.current;

    if (!section || !content) return;

    // Store ScrollTrigger instances for cleanup
    const triggers = [];

    // Create context for better performance
    const ctx = gsap.context(() => {
      // Content animations
      const timeline = gsap.timeline({
        scrollTrigger: {
          trigger: section,
          start: 'top 80%',
          end: 'bottom 20%',
          toggleActions: 'play none none reverse',
          fastScrollEnd: true,
          preventOverlaps: true,
          refreshPriority: 1,
          invalidateOnRefresh: true
        }
      });

      // Set initial states
      gsap.set(['.section-label', '.title', '.description', '.feature-item'], {
        opacity: 0,
        y: function(i) { return 20 + (i * 10); }
      });

      // Animate content elements with optimized selectors
      timeline
        .to('.section-label', 
          { opacity: 1, y: 0, duration: 0.6 }
        )
        .to('.title',
          { opacity: 1, y: 0, duration: 0.8 },
          '-=0.3'
        )
        .to('.description',
          { opacity: 1, y: 0, duration: 0.8 },
          '-=0.4'
        )
        .to('.feature-item',
          { 
            opacity: 1, 
            y: 0, 
            duration: 0.6,
            stagger: 0.1,
            ease: 'power2.out'
          },
          '-=0.3'
        );

      triggers.push(timeline.scrollTrigger);

      // Floating shape parallax
      if (floating) {
        const floatingTrigger = gsap.to(floating, {
          y: -100,
          x: 50,
          force3D: true,
          scrollTrigger: {
            trigger: section,
            start: 'top bottom',
            end: 'bottom top',
            scrub: 1.5,
            fastScrollEnd: true,
            refreshPriority: 0,
            invalidateOnRefresh: true
          }
        });
        
        if (floatingTrigger.scrollTrigger) {
          triggers.push(floatingTrigger.scrollTrigger);
        }
      }
    }, content);

    // Cleanup
    return () => {
      ctx.revert(); // This kills all GSAP animations and ScrollTriggers in context
    };
  }, []);

  return (
    <AboutSection ref={sectionRef}>
      <FloatingShape 
        ref={floatingRef}
        style={{
          top: '20%',
          right: '-300px',
        }}
      />
      
      <Container>
        <Grid>
          <ContentColumn ref={contentRef}>
            <SectionLabel className="section-label">About Me</SectionLabel>
            <Title className="title">
              Get to Know me.
            </Title>
            <Description className="description">
              I'm a 24-year-old developer from Germany. Since 2020, I've been specializing in 
              FiveM development, creating custom scripts, optimizing server performance, and 
              building immersive roleplay environments for communities of all sizes. My journey 
              led me to become ESX Development Lead in 2024 and ESX Project Lead in 2025. 
              From small projects to large servers with up to 1,000 concurrent players, I've 
              acquired the skills and knowledge to ensure your project doesn't just succeed, 
              but thrives.
            </Description>
            
            <motion.h3 
              style={{ 
                fontSize: 'var(--text-2xl)', 
                marginBottom: 'var(--space-xl)', 
                color: 'var(--color-text-primary)' 
              }}
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.6, delay: 0.3 }}
            >
              What I Offer
            </motion.h3>
            
            <FeatureGrid>
              {features.map((feature, index) => (
                <FeatureItem key={index} className="feature-item">
                  <FeatureIcon>{feature.icon}</FeatureIcon>
                  <FeatureText>
                    <FeatureTitle>{feature.title}</FeatureTitle>
                    <FeatureDescription>{feature.description}</FeatureDescription>
                  </FeatureText>
                </FeatureItem>
              ))}
            </FeatureGrid>
            
            <StatsCounter />
          </ContentColumn>
          
          <ContentColumn>
            <Timeline />
          </ContentColumn>
        </Grid>
      </Container>
    </AboutSection>
  );
});

About.displayName = 'About';

export default About;